def clean_metadata(raw_data):
    cleaned_list = []
    for item in raw_data:
        try:
            item_id = str(item.get('prod_id') or item.get('id_num') or item.get('p_id') or item.get('item_id') or item.get('id'))
            price_val = float(item.get('price_val') or item.get('cost') or item.get('price') or item.get('val'))
            currency = item.get('currency') or item.get('curr') or item.get('currency_code')
            stock_status = item.get('stock_status') or item.get('availability') or item.get('status')
            in_stock = stock_status == "in_stock"

            cleaned_list.append({
                "id": item_id,
                "price": price_val,
                "currency": currency,
                "in_stock": in_stock
            })
        except Exception:
            pass  # Silently ignore any
